List<OscarWinner> _byAward(String tag) =>
    _allAwardWinners.where((w) => w.awards.contains(tag)).toList(growable: false);

/// Academy Award Best Picture winners, 1927–present.
final List<OscarWinner> kBestPictureWinners = _byAward('bestPicture');

/// Cannes Palme d'Or winners, 1955–present.
final List<OscarWinner> kPalmeDorWinners = _byAward('palmeDor');

/// BAFTA Best Film winners (selected pre-1990 + full 1990–present).
final List<OscarWinner> kBaftaBestFilmWinners = _byAward('baftaBestFilm');

/// Golden Globe Best Motion Picture – Drama winners, 1990–present.
final List<OscarWinner> kGoldenGlobeDramaWinners = _byAward('goldenGlobeDrama');

/// Golden Globe Best Motion Picture – Musical or Comedy winners, 1990–present.
final List<OscarWinner> kGoldenGlobeMusicalComedyWinners =
    _byAward('goldenGlobeMusicalComedy');

/// Deduped union — every film that won at least one supported award.
/// Backs the 'Any award' filter on Home.
const List<OscarWinner> kAnyAwardWinners = _allAwardWinners;

enum AwardCategory {
  /// No award filter — show everything.
  none,
  /// Any supported award — union of all per-category lists.
  any,
  bestPicture,
  palmeDor,
  baftaBestFilm,
  goldenGlobeDrama,
  goldenGlobeMusicalComedy,
}

extension AwardCategoryLabel on AwardCategory {
  String get label => switch (this) {
        AwardCategory.none => 'None',
        AwardCategory.any => 'Any award',
        AwardCategory.bestPicture => 'Best Picture',
        AwardCategory.palmeDor => 'Palme d\'Or',
        AwardCategory.baftaBestFilm => 'BAFTA Best Film',
        AwardCategory.goldenGlobeDrama => 'Golden Globe — Drama',
        AwardCategory.goldenGlobeMusicalComedy =>
          'Golden Globe — Musical/Comedy',
      };
}

/// Per-category lookup. `none` returns empty (no splice / no filter);
/// `any` returns the deduped union.
Map<AwardCategory, List<OscarWinner>> get kAwardWinners => {
      AwardCategory.none: const <OscarWinner>[],
      AwardCategory.any: kAnyAwardWinners,
      AwardCategory.bestPicture: kBestPictureWinners,
      AwardCategory.palmeDor: kPalmeDorWinners,
      AwardCategory.baftaBestFilm: kBaftaBestFilmWinners,
      AwardCategory.goldenGlobeDrama: kGoldenGlobeDramaWinners,
      AwardCategory.goldenGlobeMusicalComedy:
          kGoldenGlobeMusicalComedyWinners,
    };
